from collections import defaultdict

class TrieNode:
  def __init__(self):
    self.children = defaultdict(TrieNode)
    self.endOfWord = False

class Trie:
  def __init__(self):
    self.root = TrieNode()

  def insert(self, word):
    node = self.root
    for c in word:
      node = node.children[c]
    node.endOfWord = True

def main():
  trie = Trie()
  for _ in range(int(input())):
    trie.insert(input())

  for _ in range(int(input())):
    word = input()
    print(trie.root.endOfWord)

if __name__ == '__main__':
  main()

