#include <iostream>
#include <string>

class TrieNode {
  std::unordered_map<char, TrieNode*> children;
  bool endOfWord;
};

class Trie {
  TrieNode* root;

public:
  Trie() : root(new TrieNode()) {}

  void insert(const std::string& word) {
    TrieNode* node = root;
    for (char c : word) {
      node = node->children[c];
      if (!node) node = new TrieNode();
    }
    node->endOfWord = true;
  }

  ~Trie() {
    std::unordered_map<char, TrieNode*> next_level;
    std::function<void(TrieNode*)> dfs = [&](TrieNode* node) {
      for (auto& child : node->children) {
        dfs(child.second);
      }
      next_level.erase(node);
    };
    dfs(root);
    delete root;
  }
};

int main()
{
  Trie trie;
  int t;
  std::cin >> t;
  while (t--) {
    std::string word;
    std::cin >> word;
    trie.insert(word);
  }

  int q;
  std::cin >> q;
  while (q--) {
    std::string word;
    std::cin >> word;
    std::cout << (trie.root->endOfWord ? "true" : "false") << std::endl;
  }

  return 0;
}
